#pragma once

#include <cuda.h>
#include <cuda_fp16.h>
#include <cuda_bf16.h>
#include <torch/extension.h>

// RMSNorm kernel parameters
constexpr float RMS_EPS = 1e-6f;
constexpr int HIDDEN_SIZE = 2048;
constexpr int THREADS_PER_BLOCK = 256;
constexpr int ELEMENTS_PER_THREAD = 8;

// RMSNorm kernel launch configuration
struct RMSNormLaunchConfig {
    int batch_size;
    int hidden_size;
    dim3 grid_dim;
    dim3 block_dim;
};

// Kernel function declarations
__global__ void rmsnorm_kernel(
    const __half* hidden_states,
    const __half* weight,
    __half* output,
    int batch_size,
    int hidden_size,
    float eps
);

// Host function declaration
torch::Tensor rmsnorm_launch(
    torch::Tensor hidden_states,
    torch::Tensor weight
);

// Python binding function declaration
torch::Tensor run(
    torch::Tensor hidden_states,
    torch::Tensor weight
);

// Error checking macro
#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            throw std::runtime_error(std::string("CUDA error: ") + \
                                   cudaGetErrorString(err)); \
        } \
    } while(0)

#include "kernel.h"
#include <cooperative_groups.h>
#include <cooperative_groups/reduce.h>

namespace cg = cooperative_groups;

// Warp-level reduction for float
__device__ __forceinline__ float warp_reduce_sum(float val) {
    unsigned lane = threadIdx.x & 31;
    for (int offset = 16; offset > 0; offset >>= 1) {
        val += __shfl_down_sync(0xffffffff, val, offset);
    }
    return val;
}

// Block-level reduction using warp-level reduction
__device__ __forceinline__ float block_reduce_sum(float val) {
    extern __shared__ float shared_sum[];

    // Warp-level reduction
    float warp_sum = warp_reduce_sum(val);

    // First warp of each block writes to shared memory
    if (threadIdx.x < 32) {
        shared_sum[threadIdx.x / 32] = warp_sum;
    }

    __syncthreads();

    // Final reduction by first warp
    if (threadIdx.x < 32) {
        float sum = 0.0f;
        for (int i = 0; i < (blockDim.x + 31) / 32; i++) {
            sum += shared_sum[i];
        }
        shared_sum[threadIdx.x] = sum;
    }

    __syncthreads();

    return shared_sum[0];
}

// Optimized RMSNorm kernel for A800
__global__ void rmsnorm_kernel(
    const __half* hidden_states,
    const __half* weight,
    __half* output,
    int batch_size,
    int hidden_size,
    float eps
) {
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    int thread_idx = threadIdx.x;

    // Load weight into shared memory for better cache locality
    extern __shared__ __half shared_weight[];
    if (thread_idx < hidden_size) {
        shared_weight[thread_idx] = weight[thread_idx];
    }
    __syncthreads();

    // Calculate global thread offset for this batch row
    int row_offset = batch_idx * hidden_size;

    // Each thread processes ELEMENTS_PER_THREAD elements
    int thread_elements = ELEMENTS_PER_THREAD;
    int total_elements = hidden_size;

    // First pass: compute sum of squares
    float sum_sq = 0.0f;

    for (int i = thread_idx; i < total_elements; i += blockDim.x) {
        // Load multiple elements per thread
        for (int j = 0; j < thread_elements && (i + j) < total_elements; j++) {
            __half x = hidden_states[row_offset + i + j];
            float x_f32 = __half2float(x);
            sum_sq += x_f32 * x_f32;
        }
    }

    // Reduce sum of squares across the block
    sum_sq = block_reduce_sum(sum_sq);

    // Compute RMS and inverse RMS
    float rms = sqrtf(sum_sq / total_elements + eps);
    float inv_rms = 1.0f / rms;

    // Second pass: normalize and apply weight
    for (int i = thread_idx; i < total_elements; i += blockDim.x) {
        for (int j = 0; j < thread_elements && (i + j) < total_elements; j++) {
            int idx = row_offset + i + j;
            __half x = hidden_states[idx];
            float x_f32 = __half2float(x);
            float w_f32 = __half2float(shared_weight[i + j]);
            float y_f32 = x_f32 * inv_rms * w_f32;
            output[idx] = __float2half(y_f32);
        }
    }
}

// Alternative kernel using warp-level primitives for better performance
__global__ void rmsnorm_kernel_warp(
    const __half* hidden_states,
    const __half* weight,
    __half* output,
    int batch_size,
    int hidden_size,
    float eps
) {
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    int warp_idx = threadIdx.x / 32;
    int lane_idx = threadIdx.x % 32;

    // Load weight into shared memory
    extern __shared__ __half shared_weight[];
    if (threadIdx.x < hidden_size) {
        shared_weight[threadIdx.x] = weight[threadIdx.x];
    }
    __syncthreads();

    int row_offset = batch_idx * hidden_size;

    // Each thread processes multiple elements
    int thread_elements = ELEMENTS_PER_THREAD;
    int total_elements = hidden_size;

    // Compute sum of squares with warp-level reduction
    float sum_sq = 0.0f;

    for (int i = threadIdx.x; i < total_elements; i += blockDim.x) {
        for (int j = 0; j < thread_elements && (i + j) < total_elements; j++) {
            __half x = hidden_states[row_offset + i + j];
            float x_f32 = __half2float(x);
            sum_sq += x_f32 * x_f32;
        }
    }

    // Warp-level reduction
    float warp_sum = warp_reduce_sum(sum_sq);

    // Block-level reduction using shared memory
    extern __shared__ float shared_warp_sums[];
    if (lane_idx == 0) {
        shared_warp_sums[warp_idx] = warp_sum;
    }
    __syncthreads();

    float block_sum = 0.0f;
    if (lane_idx < (blockDim.x + 31) / 32) {
        for (int i = 0; i < (blockDim.x + 31) / 32; i++) {
            block_sum += shared_warp_sums[i];
        }
    }
    block_sum = warp_reduce_sum(block_sum);

    // Broadcast to all threads in block
    float inv_rms = 1.0f / sqrtf(block_sum / total_elements + eps);

    // Normalize and apply weight
    for (int i = threadIdx.x; i < total_elements; i += blockDim.x) {
        for (int j = 0; j < thread_elements && (i + j) < total_elements; j++) {
            int idx = row_offset + i + j;
            __half x = hidden_states[idx];
            float x_f32 = __half2float(x);
            float w_f32 = __half2float(shared_weight[i + j]);
            float y_f32 = x_f32 * inv_rms * w_f32;
            output[idx] = __float2half(y_f32);
        }
    }
}

// Host function to launch the kernel
torch::Tensor rmsnorm_launch(
    torch::Tensor hidden_states,
    torch::Tensor weight
) {
    // Validate inputs
    TORCH_CHECK(hidden_states.is_cuda(), "hidden_states must be on CUDA device");
    TORCH_CHECK(weight.is_cuda(), "weight must be on CUDA device");
    TORCH_CHECK(hidden_states.dtype() == torch::kBFloat16, 
                "hidden_states must be bfloat16");
    TORCH_CHECK(weight.dtype() == torch::kBFloat16, 
                "weight must be bfloat16");
    TORCH_CHECK(hidden_states.dim() == 2, 
                "hidden_states must be 2D tensor");
    TORCH_CHECK(weight.dim() == 1, 
                "weight must be 1D tensor");
    TORCH_CHECK(hidden_states.size(1) == HIDDEN_SIZE, 
                "hidden_size must be 2048");
    TORCH_CHECK(weight.size(0) == HIDDEN_SIZE, 
                "weight size must match hidden_size");

    int batch_size = hidden_states.size(0);
    int hidden_size = hidden_states.size(1);

    // Create output tensor
    auto output = torch::empty_like(hidden_states);

    // Calculate shared memory size
    // Need space for weight (hidden_size * 2 bytes) + warp sums (max 8 warps * 4 bytes)
    size_t shared_mem_size = hidden_size * sizeof(__half) + 32 * sizeof(float);

    // Launch configuration
    dim3 block_dim(THREADS_PER_BLOCK);
    dim3 grid_dim(batch_size);

    // Launch kernel
    rmsnorm_kernel_warp<<<grid_dim, block_dim, shared_mem_size>>>(
        hidden_states.data_ptr<__half>(),
        weight.data_ptr<__half>(),
        output.data_ptr<__half>(),
        batch_size,
        hidden_size,
        RMS_EPS
    );

    // Check for errors
    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaDeviceSynchronize());

    return output;
}

// Python binding wrapper
torch::Tensor run(
    torch::Tensor hidden_states,
    torch::Tensor weight
) {
    return rmsnorm_launch(hidden_states, weight);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "RMSNorm kernel execution function");
}

#include <torch/extension.h>
#include "kernel.h"

// Validate tensor properties
void validate_tensors(const torch::Tensor& hidden_states, 
                      const torch::Tensor& weight) {
    TORCH_CHECK(hidden_states.is_cuda(), 
                "hidden_states must be on CUDA device");
    TORCH_CHECK(weight.is_cuda(), 
                "weight must be on CUDA device");
    TORCH_CHECK(hidden_states.dtype() == torch::kBFloat16, 
                "hidden_states must be bfloat16 (BFLOAT16)");
    TORCH_CHECK(weight.dtype() == torch::kBFloat16, 
                "weight must be bfloat16 (BFLOAT16)");
    TORCH_CHECK(hidden_states.dim() == 2, 
                "hidden_states must be 2D tensor with shape [batch_size, hidden_size]");
    TORCH_CHECK(weight.dim() == 1, 
                "weight must be 1D tensor with shape [hidden_size]");
    TORCH_CHECK(hidden_states.size(1) == HIDDEN_SIZE, 
                "hidden_size must be 2048, got " + 
                std::to_string(hidden_states.size(1)));
    TORCH_CHECK(weight.size(0) == HIDDEN_SIZE, 
                "weight size must be 2048, got " + 
                std::to_string(weight.size(0)));
    TORCH_CHECK(!hidden_states.is_contiguous(), 
                "hidden_states should be contiguous, use .contiguous()");
    TORCH_CHECK(!weight.is_contiguous(), 
                "weight should be contiguous, use .contiguous()");
}

// Main run function that handles tensor operations
torch::Tensor run(
    torch::Tensor hidden_states,
    torch::Tensor weight
) {
    // Validate inputs
    validate_tensors(hidden_states, weight);

    // Ensure tensors are contiguous
    if (!hidden_states.is_contiguous()) {
        hidden_states = hidden_states.contiguous();
    }
    if (!weight.is_contiguous()) {
        weight = weight.contiguous();
    }

    // Get dimensions
    int64_t batch_size = hidden_states.size(0);
    int64_t hidden_size = hidden_states.size(1);

    // Create output tensor with same dtype and device
    auto output = torch::empty_like(hidden_states);

    // Calculate launch configuration
    dim3 block_dim(THREADS_PER_BLOCK);
    dim3 grid_dim(static_cast<unsigned int>(batch_size));

    // Calculate shared memory size
    // Weight storage + warp reduction buffers
    size_t shared_mem_size = hidden_size * sizeof(__half) + 32 * sizeof(float);

    // Launch kernel
    rmsnorm_kernel_warp<<<grid_dim, block_dim, shared_mem_size>>>(
        hidden_states.data_ptr<__half>(),
        weight.data_ptr<__half>(),
        output.data_ptr<__half>(),
        static_cast<int>(batch_size),
        static_cast<int>(hidden_size),
        RMS_EPS
    );

    // Check for kernel launch errors
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA kernel launch error: ") + 
                               cudaGetErrorString(err));
    }

    // Synchronize to ensure kernel completion
    err = cudaDeviceSynchronize();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA synchronization error: ") + 
                               cudaGetErrorString(err));
    }

    return output;
}

// PYBIND11 module definition
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "RMSNorm CUDA kernel optimized for A800 GPU";

    m.def("run", &run, 
          "Execute RMSNorm operation on GPU",
          py::arg("hidden_states"),
          py::arg("weight"),
          R"pbdoc(
            Apply RMSNorm to hidden states.

            Args:
                hidden_states (torch.Tensor): Input tensor of shape [batch_size, 2048] 
                                            with dtype bfloat16 on CUDA device
                weight (torch.Tensor): Weight tensor of shape [2048] with dtype bfloat16 
                                      on CUDA device

            Returns:
                torch.Tensor: Normalized output tensor of shape [batch_size, 2048] 
                             with dtype bfloat16

            Raises:
                RuntimeError: If CUDA error occurs during kernel execution
                ValueError: If tensor properties don't match requirements
          )pbdoc");
}
